    writeFileSync(join(this.dir, `${name}.json`), JSON.stringify(teammate, null, 2));
    return JSON.stringify(teammate, null, 2);
  }

  remove(name: string) {
    this.teammates.delete(name);
    return `Removed teammate ${name}`;
  }
}

